module top_module(
  input clk,
  input rst,
  input [3:0] bin,
  output reg [3:0] obf_bcd
);always @ (posedge clk) begin
    if (rst) begin
      obf_bcd <= 4'b0;
    end else begin
      case (bin)
        4'b0000: obf_bcd <= 4'b0000;
        4'b0001: obf_bcd <= 4'b0001;
        4'b0010: obf_bcd <= 4'b0010;
        4'b0011: obf_bcd <= 4'b0011;
        4'b0100: obf_bcd <= 4'b0100;
        4'b0101: obf_bcd <= 4'b0101;
        4'b0110: obf_bcd <= 4'b0110;
        4'b0111: obf_bcd <= 4'b0111;
        4'b1000: obf_bcd <= 4'b1000;
        4'b1001: obf_bcd <= 4'b1001;
        4'b1010: obf_bcd <= 4'b0001;
        4'b1011: obf_bcd <= 4'b0010;
        4'b1100: obf_bcd <= 4'b0011;
        4'b1101: obf_bcd <= 4'b0100;
        4'b1110: obf_bcd <= 4'b0101;
        4'b1111: obf_bcd <= 4'b0110;
      endcase
    end
  end

endmodule
